import React, { useState, useEffect, useRef } from 'react';
import ApiService from './services/api';
import KPIStrip from './components/KPIStrip';
import SubmissionTable from './components/SubmissionTable';
import InterventionQueue from './components/InterventionQueue';
import RegionalBreakdown from './components/RegionalBreakdown';
import ROIPanel from './components/ROIPanel';
import FilterBar from './components/FilterBar';
import SubmissionModal from './components/SubmissionModal';
import './App.css';

function App() {
  const [kpis, setKpis] = useState(null);
  const [submissions, setSubmissions] = useState([]);
  const [interventions, setInterventions] = useState([]);
  const [regions, setRegions] = useState([]);
  const [roiData, setRoiData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedSubmission, setSelectedSubmission] = useState(null);
  const [filters, setFilters] = useState({
    region: 'all',
    sector: 'all',
    status: 'all',
    days: 9999
  });

  // Track in-flight requests so we can cancel stale ones
  const fetchIdRef = useRef(0);

  const fetchAll = async (activeFilters) => {
    // Increment fetch ID — any previous in-flight fetch will see its ID is stale and bail
    const thisFetchId = ++fetchIdRef.current;

    setLoading(true);
    setError(null);

    try {
      console.log('Fetching with filters:', activeFilters);

      const [kpiData, submissionsData, interventionsData, regionsData, roiScenarios] = await Promise.all([
        ApiService.getKPIs(activeFilters),
        ApiService.getSubmissions(activeFilters),
        ApiService.getInterventions(),
        ApiService.getRegionalBreakdown(),
        ApiService.getROIScenarios(),
      ]);

      // If a newer fetch has started since this one, discard these results
      if (thisFetchId !== fetchIdRef.current) {
        console.log('Discarding stale fetch', thisFetchId);
        return;
      }

      console.log('Submissions received:', submissionsData?.length, submissionsData?.[0]);

      setKpis(kpiData);
      setSubmissions(submissionsData);
      setInterventions(interventionsData);
      setRegions(regionsData);
      setRoiData(roiScenarios);
    } catch (err) {
      if (thisFetchId !== fetchIdRef.current) return;
      console.error('Fetch error:', err);
      setError('Failed to load dashboard data. Please check your Teradata connection.');
    } finally {
      if (thisFetchId === fetchIdRef.current) {
        setLoading(false);
      }
    }
  };

  // Single effect — runs on mount and every time filters change
  useEffect(() => {
    fetchAll(filters);
  }, [filters]); // eslint-disable-line react-hooks/exhaustive-deps

  // Auto-refresh every 5 minutes
  useEffect(() => {
    const interval = setInterval(() => fetchAll(filters), 300000);
    return () => clearInterval(interval);
  }, [filters]); // eslint-disable-line react-hooks/exhaustive-deps

  const handleFilterChange = (newFilters) => {
    setFilters(prev => ({ ...prev, ...newFilters }));
  };

  const handleSubmissionClick = async (protocolId) => {
    try {
      const details = await ApiService.getSubmissionDetails(protocolId);
      setSelectedSubmission(details);
    } catch (err) {
      console.error('Error fetching submission details:', err);
      alert('Failed to load submission details');
    }
  };

  const handleRegionClick = (regionName) => {
    setFilters(prev => ({ ...prev, region: regionName }));
  };

  if (loading && !kpis) {
    return (
      <div className="loading-screen">
        <div className="loading-spinner"></div>
        <p>Loading Regulatory Intelligence...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-screen">
        <h2>Connection Error</h2>
        <p>{error}</p>
        <button onClick={() => fetchAll(filters)}>Retry</button>
      </div>
    );
  }

  return (
    <div className="app">
      <header className="header">
        <div className="header-left">
          <div className="logo-mark"></div>
          <div className="logo-text">
            Regulatory <span className="accent">Intelligence</span> Command Center
          </div>
        </div>
        <div className="header-meta">
          <span className="live-badge">
            <span className="live-dot"></span>LIVE
          </span>
          <span>Last refresh: {new Date().toLocaleTimeString()}</span>
          <span>User: RA.Operations</span>
          <button onClick={() => fetchAll(filters)} className="refresh-btn">🔄 Refresh</button>
        </div>
      </header>

      <FilterBar filters={filters} onFilterChange={handleFilterChange} />

      {kpis && <KPIStrip kpis={kpis} />}

      <div className="main-grid">
        <div className="panel submission-panel">
          <div className="panel-header">
            <div className="panel-title">Active Submissions — Regulatory Status</div>
            <div className="panel-badge">{loading ? 'UPDATING...' : 'LIVE TRACKING'}</div>
          </div>
          <SubmissionTable submissions={submissions} onSubmissionClick={handleSubmissionClick} />
        </div>

        <div className="panel intervention-panel">
          <div className="panel-header">
            <div className="panel-title">Intervention Queue</div>
            <div className="panel-badge">
              {interventions.filter(i => i.Risk_Score >= 8).length} URGENT
            </div>
          </div>
          <InterventionQueue interventions={interventions} onInterventionClick={handleSubmissionClick} />
        </div>
      </div>

      {roiData && <ROIPanel roiData={roiData} />}

      {regions && (
        <RegionalBreakdown
          regions={regions}
          onRegionClick={handleRegionClick}
          selectedRegion={filters.region}
        />
      )}

      {selectedSubmission && (
        <SubmissionModal
          submission={selectedSubmission}
          onClose={() => setSelectedSubmission(null)}
        />
      )}

      <footer className="footer">
        <div className="footer-left">hcls · Teradata · v3.0</div>
        <div className="footer-right">Enterprise Pharmaceutical — Regulatory Affairs Analytics</div>
      </footer>
    </div>
  );
}

export default App;
